#include <stdio.h>
#include <string.h>
#include <ctype.h>

char firstNonRepeatingChar(const char *str) {
    int count[256] = {0}; // Assuming ASCII characters
    int i;

    // Count frequency of each character
    for (i = 0; str[i]; i++) {
        count[tolower(str[i])]++;
    }

    // Find the first non-repeating character
    for (i = 0; str[i]; i++) {
        if (count[tolower(str[i])] == 1) {
            return str[i];
        }
    }

    // If no non-repeating character found
    return '\0';
}

int main() {
    const char *str = "abaccdeff";
    char result = firstNonRepeatingChar(str);

    if (result) {
        printf("First non-repeating character: %c\n", result);
    } else {
        printf("No non-repeating character found.\n");
    }

    return 0;
}
```

This program uses a frequency count array `count` to keep track of the occurrence of each character in the string. It then iterates through the string again to find the first character with a count of 1. If no such character is found, it returns `\0`. Note that this program is case-insensitive due to the use of `tolower`.
